import javax.naming.*;
import javax.naming.directory.*;
import java.util.*;

public class LdapUserSearch {
    
    public static Map<String, String> searchUserByUsername(String ldapUrl, String bindDn, String bindPassword, 
                                                          String searchBase, String username) {
        Map<String, String> userAttributes = new HashMap<>();
        
        try {
            // Create environment for LDAP connection
            Hashtable<String, String> env = new Hashtable<>();
            env.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
            env.put(Context.PROVIDER_URL, ldapUrl);
            env.put(Context.SECURITY_AUTHENTICATION, "simple");
            env.put(Context.SECURITY_PRINCIPAL, bindDn);
            env.put(Context.SECURITY_CREDENTIALS, bindPassword);
            
            // Disable SSL hostname verification for demonstration - should be configured properly in production
            env.put("com.sun.jndi.ldap.object.trustUserProvider", "true");
            
            DirContext ctx = new InitialDirContext(env);
            
            // Create search controls
            SearchControls searchControls = new SearchControls();
            searchControls.setSearchScope(SearchControls.SUBTREE_SCOPE);
            
            // Define attributes to retrieve
            String[] returningAttributes = {"mail", "cn", "department", "sn", "givenName"};
            searchControls.setReturningAttributes(returningAttributes);
            
            // Build search filter
            String searchFilter = "(&(objectClass=person)(sAMAccountName=" + escapeFilterValue(username) + "))";
            
            // Perform search
            NamingEnumeration<SearchResult> results = ctx.search(searchBase, searchFilter, searchControls);
            
            if (results.hasMore()) {
                SearchResult result = results.next();
                Attributes attributes = result.getAttributes();
                
                // Extract user attributes
                Attribute mail = attributes.get("mail");
                Attribute cn = attributes.get("cn");
                Attribute department = attributes.get("department");
                
                userAttributes.put("email", mail != null ? mail.get().toString() : "");
                userAttributes.put("fullName", cn != null ? cn.get().toString() : "");
                userAttributes.put("department", department != null ? department.get().toString() : "");
            }
            
            ctx.close();
            
        } catch (NamingException e) {
            throw new RuntimeException("LDAP search failed", e);
        }
        
        return userAttributes;
    }
    
    private static String escapeFilterValue(String value) {
        if (value == null) {
            return "";
        }
        
        StringBuilder escaped = new StringBuilder();
        for (char c : value.toCharArray()) {
            switch (c) {
                case '\\':
                    escaped.append("\\5c");
                    break;
                case '*':
                    escaped.append("\\2a");
                    break;
                case '(':
                    escaped.append("\\28");
                    break;
                case ')':
                    escaped.append("\\29");
                    break;
                case '\0':
                    escaped.append("\\00");
                    break;
                default:
                    escaped.append(c);
            }
        }
        return escaped.toString();
    }
}